css:
/* Animate.css Library Import & Custom Variables */
@import url('https://cdnjs.cloudflare.com/ajax/libs/animate.css/4.1.1/animate.min.css');

.preview-object {
  --animate-duration: 1s;
  animation-delay: 0s;
  transition: all 0.2s ease;
}

js:
// JS Trigger Logic
function playAnimation(aniName) {
  const el = document.getElementById('preview-box');
  el.className = 'preview-object'; // Reset class
  void el.offsetWidth; // Trigger reflow
  el.classList.add('animate__animated', `animate__${aniName}`);
}
